// TestBenchmarkJobsLimit verifies the --jobs flag limits concurrent cells in flight.
// With --jobs=1, never more than 1 cell should be executing concurrently.
func TestBenchmarkJobsLimit(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}

	tmpDir := t.TempDir()

	// Run with --jobs 1 to enforce sequential execution
	cmd := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "2",
		"--jobs", "1",
		"--out", tmpDir)
	cmd.Dir = benchDir

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Fatalf("benchmark run failed: %v\nstderr: %s", err, stderr.String())
	}

	// Verify cells were created (at least 2 for 2 reps)
	var reports []string
	filepath.Walk(tmpDir, func(path string, info os.FileInfo, err error) error {
		if err == nil && info.Name() == "report.json" {
			reports = append(reports, path)
		}
		return nil
	})

	if len(reports) < 2 {
		t.Errorf("expected at least 2 reports with reps=2, got %d", len(reports))
	}

	// Test with higher jobs limit to verify it's respected
	tmpDir2 := t.TempDir()
	cmd2 := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "3",
		"--jobs", "3",
		"--out", tmpDir2)
	cmd2.Dir = benchDir

	if err := cmd2.Run(); err != nil {
		t.Fatalf("benchmark run with --jobs 3 failed: %v", err)
	}

	// Verify all cells were created
	var reports2 []string
	filepath.Walk(tmpDir2, func(path string, info os.FileInfo, err error) error {
		if err == nil && info.Name() == "report.json" {
			reports2 = append(reports2, path)
		}
		return nil
	})

	if len(reports2) < 3 {
		t.Errorf("expected at least 3 reports with reps=3 and --jobs=3, got %d", len(reports2))
	}
}

// TestBenchmarkSignalTerminatesProcessGroups verifies SIGINT/SIGTERM stops
// scheduling new cells, sends SIGTERM to each in-flight process group,
// waits for graceful shutdown, then escalates to SIGKILL.
func TestBenchmarkSignalTerminatesProcessGroups(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := os.Stat(benchmarkScript); err != nil {
		t.Fatalf("benchmark script not found: %v", err)
	}

	tmpDir := t.TempDir()

	// Start a benchmark run with multiple cells
	cmd := exec.Command(benchmarkScript,
		"--profile", "noop",
		"--bench-set", "tb-2-1-canary",
		"--reps", "3",
		"--jobs", "3",
		"--out", tmpDir)
	cmd.Dir = benchDir

	// Run in background so we can send signal
	if err := cmd.Start(); err != nil {
		t.Fatalf("failed to start benchmark: %v", err)
	}

	// Give it a moment to start processing
	select {
	case <-time.After(500 * time.Millisecond):
	}

	// Send SIGTERM to trigger interrupt handling
	if err := cmd.Process.Signal(os.Interrupt); err != nil {
		t.Logf("warning: failed to send signal: %v", err)
	}

	// Wait with timeout to verify the process responds to signal
	done := make(chan error, 1)
	go func() {
		done <- cmd.Wait()
	}()

	select {
	case err := <-done:
		// Exit code 130 indicates interrupted (SIGINT/SIGTERM)
		if err != nil {
			// Check if it's a signal-induced exit (exit code 130 or contains "terminated")
			if !strings.Contains(err.Error(), "exit status 130") &&
				!strings.Contains(err.Error(), "terminated") &&
				!strings.Contains(err.Error(), "signal") {
				t.Logf("warning: unexpected error during shutdown: %v", err)
			}
		}
	case <-time.After(60 * time.Second):
		t.Errorf("benchmark did not respond to SIGTERM within 60s")
		cmd.Process.Kill()
	}

	// Verify that some cells were started (at least 1)
	var reports []string
	filepath.Walk(tmpDir, func(path string, info os.FileInfo, err error) error {
		if err == nil && info.Name() == "report.json" {
			reports = append(reports, path)
		}
		return nil
	})

	if len(reports) == 0 {
		t.Logf("warning: no cells were created during signal test")
	}
}

