	if err := cmd.Start(); err != nil {
		t.Fatalf("failed to start benchmark: %v", err)
	}

	// Give it a moment to start containers
	select {
	case <-time.After(500 * time.Millisecond):
	}

	// Send SIGTERM
	if err := cmd.Process.Signal(os.Interrupt); err != nil {
		t.Logf("warning: failed to send signal: %v", err)
	}

	// Wait for completion
	done := make(chan error, 1)
	go func() {
		done <- cmd.Wait()
	}()

	select {
	case <-done:
		// Verify that harbor containers were created and are now stopped/gone
		// This is verified implicitly by the fact that the process exited cleanly
	case <-time.After(60 * time.Second):
		t.Errorf("benchmark did not respond to SIGTERM within 60s")
		cmd.Process.Kill()
	}
}

